           float sv = util::f16_to_f32(static_cast<uint16_t>(
               ((amdgpu::vop3_opsel(inst_) & 0x1u) != 0 ? (src0.read_lane(wf, lane) >> 16)
                                                        : src0.read_lane(wf, lane))));
